example_bad:
struct User {
    name: String,
    email: String,
    age: u32,
}

fn main() {
    let u = User {
        name: String::from("Alice"),
        // Error: missing fields `email` and `age`
    };
}

fixes.code:
let u = User {
    name: String::from("Alice"),
    email: String::from("alice@example.com"),
    age: 30,
};

#[derive(Default)]
struct User {
    name: String,
    email: String,
    age: u32,
}

let u = User {
    name: String::from("Alice"),
    ..Default::default() // Fill remaining with defaults
};

let template = User {
    name: String::from(""),
    email: String::from(""),
    age: 0,
};

let u = User {
    name: String::from("Alice"),
    ..template
};
